  const colorScheme = (settings["colorScheme"] as string) || "scheme-1";
  return (
    <div
      className="rounded-lg p-4 text-gray-400"
      data-color-scheme={colorScheme}
    >
      <p className="text-sm italic">Rich text content area</p>
