import type { BlockInstance } from "../../../types/page-builder";
import { getBlockTypographyStyles } from "../theme-styles";

interface FrontendTextAtomSectionProps {
  settings: Record<string, unknown>;
  blocks: BlockInstance[];
}

export function FrontendTextAtomSection({
  settings,
  blocks,
}: FrontendTextAtomSectionProps): React.ReactNode {
  const text = (settings["text"] as string) || "";
  const alignment = (settings["alignment"] as string) || "left";
  const letterGap = (settings["letterGap"] as number) || 0;
  const lineGap = (settings["lineGap"] as number) || 0;
  const wrap = (settings["wrap"] as string) || "wrap";
  const letters = blocks.length
    ? blocks
    : Array.from(text).map((char: string, index: number): BlockInstance => ({
        id: `text-atom-section-${index}`,
        type: "TextAtomLetter",
        settings: { textContent: char },
      }));

  if (!letters.length) return null;

  const justifyContent =
    alignment === "center"
      ? "center"
      : alignment === "right"
        ? "flex-end"
        : "flex-start";

  const containerStyle: React.CSSProperties = {
    display: "flex",
    flexWrap: wrap === "nowrap" ? "nowrap" : "wrap",
    justifyContent,
    alignItems: "baseline",
    columnGap: letterGap,
    rowGap: lineGap,
    whiteSpace: wrap === "nowrap" ? "pre" : "pre-wrap",
  };

  return (
    <section className="m-0 w-full p-0">
      <div style={containerStyle}>
        {letters.map((letter: BlockInstance) => {
          const textContent = (letter.settings["textContent"] as string) ?? "";
          const typoStyles = getBlockTypographyStyles(letter.settings);
          return (
            <span
              key={letter.id}
              className="inline-block"
              style={{ ...typoStyles, whiteSpace: "pre" }}
            >
              {textContent}
            </span>
          );
        })}
      </div>
    </section>
  );
}

"use client";

import React, { useMemo } from "react";
import type { BlockDefinition } from "../../types/page-builder";
import { getAllowedBlockTypes } from "./section-registry";
import { useSettingsMap } from "@/shared/hooks/use-settings";
import { parseJsonSetting } from "@/shared/utils/settings-json";
import { APP_EMBED_SETTING_KEY, type AppEmbedId } from "@/features/app-embeds/lib/constants";
import { PickerDropdown } from "./PickerDropdown";

interface BlockPickerProps {
  sectionType: string;
  onSelect: (blockType: string) => void;
}

export function BlockPicker({ sectionType, onSelect }: BlockPickerProps): React.ReactNode {
  const settingsQuery = useSettingsMap();
  const enabledEmbeds = useMemo<AppEmbedId[]>(() => {
    if (!settingsQuery.data) return [];
    return parseJsonSetting<AppEmbedId[]>(
      settingsQuery.data.get(APP_EMBED_SETTING_KEY),
      []
    );
  }, [settingsQuery.data]);
  const hasAppEmbeds = enabledEmbeds.length > 0;
  const blockTypes = getAllowedBlockTypes(sectionType).filter((def: BlockDefinition) => {
    if (def.type !== "AppEmbed") return true;
    return hasAppEmbeds;
  });

  const groups = useMemo(() => [
    {
      label: "Blocks",
      options: blockTypes.map((def: BlockDefinition) => ({
        type: def.type,
        label: def.label,
      })),
    },
  ], [blockTypes]);

  if (blockTypes.length === 0) return null;

  return (
    <PickerDropdown
      groups={groups}
      onSelect={onSelect}
      ariaLabel="Add block"
    />
  );
}

"use client";

import React, { useMemo } from "react";
import type { BlockDefinition } from "../../types/page-builder";
import { getBlockDefinition, getColumnAllowedBlockTypes } from "./section-registry";
import { useSettingsMap } from "@/shared/hooks/use-settings";
import { parseJsonSetting } from "@/shared/utils/settings-json";
import { APP_EMBED_SETTING_KEY, type AppEmbedId } from "@/features/app-embeds/lib/constants";
import { PickerDropdown, type PickerGroup } from "./PickerDropdown";

const SECTION_BLOCK_TYPES = ["ImageWithText", "Hero", "RichText", "Block", "TextAtom", "Carousel", "Slideshow"];

interface ColumnBlockPickerProps {
  onSelect: (blockType: string) => void;
  allowedBlockTypes?: string[] | undefined;
}

export function ColumnBlockPicker({ onSelect, allowedBlockTypes }: ColumnBlockPickerProps): React.ReactNode {
  const settingsQuery = useSettingsMap();
  const enabledEmbeds = useMemo<AppEmbedId[]>(() => {
    if (!settingsQuery.data) return [];
    return parseJsonSetting<AppEmbedId[]>(
      settingsQuery.data.get(APP_EMBED_SETTING_KEY),
      []
    );
  }, [settingsQuery.data]);
  const hasAppEmbeds = enabledEmbeds.length > 0;
  const resolvedTypes = allowedBlockTypes
    ? allowedBlockTypes
        .map((type: string) => getBlockDefinition(type))
        .filter((def: BlockDefinition | undefined): def is BlockDefinition => Boolean(def))
    : getColumnAllowedBlockTypes();
  const allTypes = resolvedTypes.filter((def: BlockDefinition) => {
    if (def.type !== "AppEmbed") return true;
    return hasAppEmbeds;
  });
  const elementTypes = allTypes.filter((d: BlockDefinition) => !SECTION_BLOCK_TYPES.includes(d.type));
  const sectionTypes = allTypes.filter((d: BlockDefinition) => SECTION_BLOCK_TYPES.includes(d.type));

  const groups = useMemo(() => [
    {
      label: "Elements",
      options: elementTypes.map((def: BlockDefinition) => ({
        type: def.type,
        label: def.label,
      })),
    },
    {
      label: "Sections",
      options: sectionTypes.map((def: BlockDefinition) => ({
        type: def.type,
        label: def.label,
      })),
    },
  ].filter((g: PickerGroup) => g.options.length > 0), [elementTypes, sectionTypes]);

  if (allTypes.length === 0) return null;

  return (
    <PickerDropdown
      groups={groups}
      onSelect={onSelect}
      ariaLabel="Add block to column"
    />
  );
}

