  ChevronRight,
  ChevronDown,
  Heading,
  AlignLeft,
  MousePointerClick,
  Box,
  Layers,
  GripVertical,
  LayoutGrid,
  Columns,
  FileText,
  LayoutTemplate,
  ListCollapse,
  Quote,
  Video,
  GalleryHorizontal,
  Mail,
  Send,
  ImageIcon,
  Minus,
  Share2,
  Smile,
  Megaphone,
  Eye,
  EyeOff,
  Trash2,
  AppWindow,
  Plus,
  Folder,
