                  >
                    <span className="text-sm font-medium text-gray-200">{template.name}</span>
                    <span className="text-xs text-gray-500">{template.description}</span>
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>
      </DialogContent>
    </Dialog>
  );
}

import React, { useCallback, useMemo, useState } from "react";
import {
  Input,
  Label,
  Select,
  SelectContent,
