            modelUrl={modelUrl}
            backgroundColor="#111827"
            autoRotate
            autoRotateSpeed={2}
            environment="studio"
            lighting="studio"
            lightIntensity={1}
            enableShadows
            enableBloom={false}
            bloomIntensity={0.5}
            exposure={1}
            showGround={false}
            enableContactShadows
            enableVignette={false}
            autoFit
            presentationMode={false}
            className="h-full w-full"
