          size="sm"
          variant="outline"
          className="text-xs"
          onClick={(): void => setOpen(true)}
          disabled={disabled}
        >
          Browse 3D assets
        </Button>
        <Button
          type="button"
          size="sm"
          variant="outline"
          className="text-xs"
          onClick={(): void => selectedAsset && setPreviewAsset(selectedAsset)}
