                    environment="studio"
                    lighting="studio"
                    lightIntensity={1}
                    enableShadows
                    enableBloom={false}
                    bloomIntensity={0.5}
                    exposure={1}
                    showGround={false}
                    enableContactShadows
                    enableVignette={false}
                    autoFit
                    presentationMode={false}
