}: FieldProps<number> & { suffix?: string; min?: number; max?: number; step?: number }): React.JSX.Element {
  return (
    <div className={cn("space-y-1", className)}>
      {label && (
        <Label className="text-[10px] uppercase tracking-wider text-gray-500">
          {label}
        </Label>
