              return b;
            }).filter(Boolean);
          };
          return { ...s, blocks: removeFromBlocks(s.blocks) };
        });
        return { sections: nextSections, moved };
      };

      let removal = removeFromSource(state.sections, action.fromSectionId, action.fromColumnId, action.fromParentBlockId);
      if (!removal.moved) {
