const updateDraft_Mongo = async (id: string, input: UpdateProductDraftInput): Promise<ProductDraft | null> => {
  const mongo = await getMongoDb();
  const now = new Date();
  const updatePayload: Partial<MongoDraftDoc> = { ...input };
  if ("categoryId" in input) {
    const normalized = typeof input.categoryId === "string" && input.categoryId.trim() ? input.categoryId.trim() : null;
    updatePayload.categoryId = normalized;
    updatePayload.categoryIds = normalized ? [normalized] : [];
  }

  const result = await mongo.collection<MongoDraftDoc>("product_drafts").findOneAndUpdate(
    { _id: id },
    {
      $set: {
        ...updatePayload,
        updatedAt: now,
      } as Partial<MongoDraftDoc>,
    },
    { returnDocument: "after" }
  );

  if (!result) return null;

  // Handle different MongoDB driver versions
  const doc = (typeof result === 'object' && 'value' in result) 
    ? (result.value as MongoDraftDoc | null) 
    : (result as unknown as MongoDraftDoc | null);

  if (!doc) return null;

  return {
    id: String(doc._id),
    name: doc.name || "",
    description: doc.description || null,
    sku: doc.sku || null,
    ean: doc.ean || null,
    gtin: doc.gtin || null,
    asin: doc.asin || null,
    name_en: doc.name_en || null,
    name_pl: doc.name_pl || null,
    name_de: doc.name_de || null,
    description_en: doc.description_en || null,
    description_pl: doc.description_pl || null,
    description_de: doc.description_de || null,
    weight: doc.weight || null,
    sizeLength: doc.sizeLength || null,
    sizeWidth: doc.sizeWidth || null,
    length: doc.length || null,
    price: doc.price || null,
    supplierName: doc.supplierName || null,
    supplierLink: doc.supplierLink || null,
    priceComment: doc.priceComment || null,
    stock: doc.stock || null,
    catalogIds: Array.isArray(doc.catalogIds) ? doc.catalogIds : [],
    categoryId:
      typeof doc.categoryId === "string"
        ? doc.categoryId
        : Array.isArray(doc.categoryIds)
        ? doc.categoryIds[0] ?? null
        : null,
    tagIds: Array.isArray(doc.tagIds) ? doc.tagIds : [],
    parameters: Array.isArray(doc.parameters)
      ? doc.parameters
      : [],
    defaultPriceGroupId: doc.defaultPriceGroupId || null,
    active: doc.active ?? true,
    icon: doc.icon || null,
    imageLinks: Array.isArray(doc.imageLinks) ? doc.imageLinks : [],
    baseProductId: doc.baseProductId || null,
    createdAt: doc.createdAt || now,
    updatedAt: now,
  };
};

const deleteDraft_Mongo = async (id: string): Promise<boolean> => {
  const mongo = await getMongoDb();
  const result = await mongo.collection("product_drafts").deleteOne({ _id: new ObjectId(id) });
  return result.deletedCount > 0;
};

// Prisma implementation
const listDrafts_Prisma = async (): Promise<ProductDraft[]> => {
  const drafts = await prisma.productDraft.findMany({
    orderBy: { createdAt: "desc" },
  });

  return drafts.map((draft: Prisma.ProductDraftGetPayload<Record<string, never>>) => ({
    ...draft,
    catalogIds: draft.catalogIds as string[],
    categoryId: typeof draft.categoryId === "string" ? draft.categoryId : null,
    tagIds: draft.tagIds as string[],
    parameters: draft.parameters as ProductParameterValue[],
    imageLinks: draft.imageLinks as string[],
  }));
};

const getDraft_Prisma = async (id: string): Promise<ProductDraft | null> => {
  const draft = await prisma.productDraft.findUnique({
    where: { id },
  });

  if (!draft) return null;

  return {
    ...draft,
    catalogIds: draft.catalogIds as string[],
    categoryId: typeof draft.categoryId === "string" ? draft.categoryId : null,
    tagIds: draft.tagIds as string[],
    parameters: draft.parameters as ProductParameterValue[],
    imageLinks: draft.imageLinks as string[],
  };
};

const createDraft_Prisma = async (input: CreateProductDraftInput): Promise<ProductDraft> => {
  const draft = await prisma.productDraft.create({
    data: {
      name: input.name,
      description: input.description,
      sku: input.sku,
      ean: input.ean,
      gtin: input.gtin,
      asin: input.asin,
      name_en: input.name_en,
      name_pl: input.name_pl,
      name_de: input.name_de,
      description_en: input.description_en,
      description_pl: input.description_pl,
      description_de: input.description_de,
      weight: input.weight,
      sizeLength: input.sizeLength,
      sizeWidth: input.sizeWidth,
      length: input.length,
      price: input.price,
      supplierName: input.supplierName,
      supplierLink: input.supplierLink,
      priceComment: input.priceComment,
      stock: input.stock,
      catalogIds: input.catalogIds || [],
      categoryId: input.categoryId || null,
      tagIds: input.tagIds || [],
      parameters: input.parameters || [],
      defaultPriceGroupId: input.defaultPriceGroupId,
      active: input.active ?? true,
      icon: input.icon,
      imageLinks: input.imageLinks || [],
      baseProductId: input.baseProductId,
    } as Prisma.ProductDraftCreateInput, // Type assertion needed due to exactOptionalPropertyTypes
  });

  return {
    ...draft,
    catalogIds: draft.catalogIds as string[],
    categoryId: typeof draft.categoryId === "string" ? draft.categoryId : null,
    tagIds: draft.tagIds as string[],
    parameters: draft.parameters as ProductParameterValue[],
    imageLinks: draft.imageLinks as string[],
  };
};

const updateDraft_Prisma = async (id: string, input: UpdateProductDraftInput): Promise<ProductDraft | null> => {
  try {
    const draft = await prisma.productDraft.update({
      where: { id },
      data: input as Prisma.ProductDraftUpdateInput, // Type assertion needed due to exactOptionalPropertyTypes
    });

    return {
      ...draft,
      catalogIds: draft.catalogIds as string[],
      categoryId: typeof draft.categoryId === "string" ? draft.categoryId : null,
      tagIds: draft.tagIds as string[],
      parameters: draft.parameters as ProductParameterValue[],
      imageLinks: draft.imageLinks as string[],
    };
  } catch {
    return null;
  }
};

const deleteDraft_Prisma = async (id: string): Promise<boolean> => {
  try {
    await prisma.productDraft.delete({
      where: { id },
    });
    return true;
  } catch {
    return false;
  }
};

// Public API
export const listDrafts = async (): Promise<ProductDraft[]> => {
  const provider = await getDraftProvider();
  return provider === "mongodb" ? listDrafts_Mongo() : listDrafts_Prisma();
};

export const getDraft = async (id: string): Promise<ProductDraft | null> => {
  const provider = await getDraftProvider();
  return provider === "mongodb" ? getDraft_Mongo(id) : getDraft_Prisma(id);
};

export const createDraft = async (input: CreateProductDraftInput): Promise<ProductDraft> => {
  const provider = await getDraftProvider();
  return provider === "mongodb" ? createDraft_Mongo(input) : createDraft_Prisma(input);
};

export const updateDraft = async (id: string, input: UpdateProductDraftInput): Promise<ProductDraft | null> => {
  const provider = await getDraftProvider();
  return provider === "mongodb" ? updateDraft_Mongo(id, input) : updateDraft_Prisma(id, input);
};

export const deleteDraft = async (id: string): Promise<boolean> => {
  const provider = await getDraftProvider();
  return provider === "mongodb" ? deleteDraft_Mongo(id) : deleteDraft_Prisma(id);
};

"use client";
import { FilePreviewModal, Button, useToast, Input, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, Tabs, TabsContent, TabsList, TabsTrigger, SharedModal } from "@/shared/ui";
import Image from "next/image";
import Link from "next/link";
import { useState, useMemo } from "react";
import type { ImageFileSelection } from "@/shared/types/files";
import type { ExpandedImageFile } from "@/features/products";
import { useFiles, useDeleteFile, useUpdateFileTags } from "@/features/files/hooks/useFiles";
import { useAssets3D } from "@/features/viewer3d/hooks/useAsset3dQueries";
import type { Asset3DRecord, Asset3DListFilters } from "@/features/viewer3d/types";
import { logClientError } from "@/features/observability";

interface FileManagerProps {
  onSelectFile?: (files: ImageFileSelection[]) => void;
  mode?: "view" | "select";
  showFileManager?: boolean;
  selectionMode?: "single" | "multiple";
  autoConfirmSelection?: boolean;
  showFolderFilter?: boolean;
  defaultFolder?: string;
  showBulkActions?: boolean;
  showTagSearch?: boolean;
}

// This component provides a UI for browsing and selecting existing image files.
// It fetches the list of files from the API and allows the user to filter them.
const normalizeTag = (tag: string): string => tag.trim().toLowerCase();
const parseTagInput = (input: string): string[] => {
  const raw = input.split(",").map(normalizeTag).filter(Boolean);
  return Array.from(new Set(raw));
};

export default function FileManager({
  onSelectFile,
  mode = "select",
  selectionMode = "multiple",
  autoConfirmSelection = false,
  showFolderFilter = false,
  defaultFolder,
  showBulkActions = false,
  showTagSearch = false,
}: FileManagerProps): React.JSX.Element {
  type FileKind = "upload" | "link" | "base64" | "other";

  const [filenameSearch, setFilenameSearch] = useState("");
  const [productNameSearch, setProductNameSearch] = useState("");
  const [tagSearch, setTagSearch] = useState("");
  const [bulkTagInput, setBulkTagInput] = useState("");
  const [bulkTagMode, setBulkTagMode] = useState<"add" | "replace">("add");
  const [localFolderFilter, setLocalFolderFilter] = useState<string | null>(null);
  const [previewFile, setPreviewFile] = useState<ExpandedImageFile | null>(null);
  const [previewAsset, setPreviewAsset] = useState<Asset3DRecord | null>(null);
  const [activeTab, setActiveTab] = useState<"uploads" | "links" | "base64" | "assets3d">("uploads");
  const { toast } = useToast();
  const deleteFileMutation = useDeleteFile();
  const updateTagsMutation = useUpdateFileTags();

  const enableTagSearch = showTagSearch || showBulkActions;
  const tagSearchList = useMemo((): string[] => parseTagInput(tagSearch), [tagSearch]);

  const queryParams = useMemo((): string => {
    const query = new URLSearchParams();
    if (filenameSearch) {
      query.append("filename", filenameSearch);
    }
    if (productNameSearch) {
      query.append("productName", productNameSearch);
    }
    if (enableTagSearch && tagSearchList.length > 0) {
      query.append("tags", tagSearchList.join(","));
    }
    return query.toString();
  }, [filenameSearch, productNameSearch, tagSearchList, enableTagSearch]);

  const { data: files = [] } = useFiles(queryParams);
  const assetFilters = useMemo(() => {
    const filters: Asset3DListFilters = {
      search: filenameSearch || null,
    };
    if (enableTagSearch && tagSearchList.length > 0) {
      filters.tags = tagSearchList;
    }
    return filters;
  }, [enableTagSearch, filenameSearch, tagSearchList]);
  const { data: assets3d = [] } = useAssets3D(assetFilters);

  const getFileKind = (filepath: string): FileKind => {
    const clean = (filepath || "").trim();
    if (!clean) return "other";
    if (clean.startsWith("data:")) return "base64";
    if (/^https?:\/\//i.test(clean)) return "link";
    if (clean.includes("/uploads/") || clean.startsWith("/uploads/") || clean.startsWith("uploads/")) {
      return "upload";
    }
    return "other";
  };

  const resolveFolder = (filepath: string): string => {
    const kind = getFileKind(filepath);
    if (kind === "base64") return "base64";
    if (kind === "link") {
      try {
        return new URL(filepath).hostname || "link";
      } catch {
        return "link";
      }
    }
    const clean = filepath.replace(/^\/+/, "");
    const parts = clean.split("/");
    if (parts.length === 0) return "uploads";
    if (parts[0] === "uploads") {
      return parts[1] ?? "uploads";
    }
    return parts[0] || "uploads";
  };

  const uploadFiles = useMemo(
    () => files.filter((file: ExpandedImageFile) => {
      const kind = getFileKind(file.filepath);
      return kind === "upload" || kind === "other";
    }),
    [files]
  );

  const folderOptions = useMemo((): string[] => {
    const folders = new Set<string>();
    uploadFiles.forEach((file: ExpandedImageFile) => {
      if (file.filepath) {
        folders.add(resolveFolder(file.filepath));
      }
    });
    return ["all", ...Array.from(folders).sort()];
  }, [uploadFiles]);

  const initialFolderFilter = useMemo((): string => {
    if (defaultFolder && folderOptions.includes(defaultFolder)) {
      return defaultFolder;
    }
    return "all";
  }, [defaultFolder, folderOptions]);

  const folderFilter = localFolderFilter ?? initialFolderFilter;

  const tagOptions = useMemo((): string[] => {
    const tags = new Set<string>();
    files.forEach((file: ExpandedImageFile) => {
      (file.tags ?? []).forEach((tag: string) => tags.add(tag));
    });
    return Array.from(tags).sort();
  }, [files]);

  const filterByTab = useMemo(() => {
    if (activeTab === "links") {
      return (file: ExpandedImageFile): boolean => getFileKind(file.filepath) === "link";
    }
    if (activeTab === "base64") {
      return (file: ExpandedImageFile): boolean => getFileKind(file.filepath) === "base64";
    }
    return (file: ExpandedImageFile): boolean => {
      const kind = getFileKind(file.filepath);
      return kind === "upload" || kind === "other";
    };
  }, [activeTab]);

  const filteredFiles = useMemo((): ExpandedImageFile[] => {
    const base = files.filter(filterByTab);
    if (activeTab !== "uploads") return base;
    if (folderFilter === "all") return base;
    return base.filter((file: ExpandedImageFile) => resolveFolder(file.filepath) === folderFilter);
  }, [files, filterByTab, folderFilter, activeTab]);

  const fileById = useMemo((): Map<string, ExpandedImageFile> => {
    return new Map(files.map((file: ExpandedImageFile) => [file.id, file]));
  }, [files]);

  const [selectedFiles, setSelectedFiles] = useState<ImageFileSelection[]>([]);

  const handleClick = (file: ExpandedImageFile): void => {
    if (mode === "select") {
      handleToggleSelect({ id: file.id, filepath: file.filepath });
    } else {
      setPreviewFile(file);
    }
  };

  // This function toggles the selection of a file.
  const handleToggleSelect = (file: ImageFileSelection): void => {
    setSelectedFiles((prev: ImageFileSelection[]) =>
      selectionMode === "single"
        ? [file]
        : prev.some((f: ImageFileSelection) => f.id === file.id)
        ? prev.filter((f: ImageFileSelection) => f.id !== file.id)
        : [...prev, file]
    );
    if (selectionMode === "single" && autoConfirmSelection && onSelectFile) {
      onSelectFile([file]);
    }
  };

  // This function is called when the user confirms their selection.
  // It calls the onSelectFile callback with the selected files.
  const handleConfirmSelection = (): void => {
    if (onSelectFile) {
      onSelectFile(selectedFiles);
    }
  };

  const handleSelectAll = (): void => {
    const toSelect = filteredFiles.map((file: ExpandedImageFile) => ({ id: file.id, filepath: file.filepath }));
    setSelectedFiles(toSelect);
  };

  const handleClearSelection = (): void => {
    setSelectedFiles([]);
  };

  const handleDeleteSelected = async (): Promise<void> => {
    if (selectedFiles.length === 0) return;
    if (!confirm(`Delete ${selectedFiles.length} selected file(s)?`)) return;
    try {
      for (const file of selectedFiles) {
        await deleteFileMutation.mutateAsync(file.id);
      }
      setSelectedFiles([]);
      toast("Selected files deleted.", { variant: "success" });
    } catch (error) {
      logClientError(error, { context: { source: "FileManager", action: "deleteSelected", count: selectedFiles.length } });
      toast("Failed to delete selected files.", { variant: "error" });
    }
  };

  const handleApplyTags = async (): Promise<void> => {
    const tags = parseTagInput(bulkTagInput);
    if (selectedFiles.length === 0) {
      toast("Select at least one file to tag.", { variant: "info" });
      return;
    }
    if (tags.length === 0) {
      toast("Enter at least one tag.", { variant: "info" });
      return;
    }
    try {
      await Promise.all(
        selectedFiles.map((file: ImageFileSelection) => {
          const existing = fileById.get(file.id)?.tags ?? [];
          const nextTags = bulkTagMode === "replace"
            ? tags
            : Array.from(new Set([...existing, ...tags]));
          return updateTagsMutation.mutateAsync({ id: file.id, tags: nextTags });
        })
      );
      toast("Tags updated.", { variant: "success" });
      setBulkTagInput("");
    } catch (error) {
      logClientError(error, { context: { source: "FileManager", action: "applyTags", count: selectedFiles.length } });
      toast("Failed to update tags.", { variant: "error" });
    }
  };

  // This function sends a DELETE request to the API to delete a file.
  const handleDelete = async (fileId: string): Promise<void> => {
