  { key: "length", description: "Length" },
];

type TestResultData = { 
  analysisInitial?: string; 
  analysisFinal?: string;
  descriptionInitial?: string;
  descriptionFinal?: string;
};

interface JobData {
  status: "pending" | "running" | "completed" | "failed" | "canceled";
  result?: TestResultData & { analysis?: string; description?: string };
  errorMessage?: string;
}

export function AiDescriptionSettings(): React.JSX.Element {
  const [imageAnalysisModel, setImageAnalysisModel] = useState("");

  // Path 1
  const [visionInputPrompt, setVisionInputPrompt] = useState("");
  const [visionOutputPrompt, setVisionOutputPrompt] = useState("");
  const [visionOutputEnabled, setVisionOutputEnabled] = useState(false);

  const [descriptionGenerationModel, setDescriptionGenerationModel] = useState("");

  // Path 2
  const [generationInputPrompt, setGenerationInputPrompt] = useState("");
  const [generationOutputPrompt, setGenerationOutputPrompt] = useState("");
  const [generationOutputEnabled, setGenerationOutputEnabled] = useState(false);

  const [ollamaModels, setOllamaModels] = useState<{ value: string; label: string; description: string }[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const { toast } = useToast();

  const [testProductId, setTestProductId] = useState("");
  const [testing, setTesting] = useState(false);
  const [testResult, setTestResult] = useState<TestResultData | null>(null);
  const [queuing, setQueuing] = useState(false);

  // Use TanStack Query hooks
  const { data: settingsMap, isLoading: settingsLoading } = useSettingsMap();
  const { mutateAsync: updateSettingMutateAsync } = useUpdateSetting();

  useEffect(() => {
    if (settingsMap && !settingsLoading) {
      setImageAnalysisModel(settingsMap.get("ai_vision_model") || "gpt-4o");
      setVisionInputPrompt(settingsMap.get("ai_vision_user_prompt") || "Analyze these product images...");
      setVisionOutputPrompt(settingsMap.get("ai_vision_prompt") || "");
      setVisionOutputEnabled(settingsMap.get("ai_vision_output_enabled") === "true");
      setDescriptionGenerationModel(settingsMap.get("ai_description_model") || "gpt-4o");
      setGenerationInputPrompt(settingsMap.get("ai_description_user_prompt") || "Generate a product description...");
      setGenerationOutputPrompt(settingsMap.get("ai_description_prompt") || "");
      setGenerationOutputEnabled(settingsMap.get("ai_description_output_enabled") === "true");
      setLoading(false);
    }
  }, [settingsMap, settingsLoading]);

  useEffect(() => {
    const loadData = async (): Promise<void> => {
      try {
        const settingsRes = await fetch("/api/settings");
        let settingsMap = new Map<string, string>();
        if (settingsRes.ok) {
          const data = (await settingsRes.json()) as { key: string, value: string }[];
          settingsMap = new Map(data.map((item: { key: string, value: string }) => [item.key, item.value]));
        }

        setImageAnalysisModel(settingsMap.get("ai_vision_model") || "gpt-4o");
        setVisionInputPrompt(settingsMap.get("ai_vision_user_prompt") || "Analyze these product images...");
        setVisionOutputPrompt(settingsMap.get("ai_vision_prompt") || "");
        setVisionOutputEnabled(settingsMap.get("ai_vision_output_enabled") === "true");

        setDescriptionGenerationModel(settingsMap.get("openai_model") || "gpt-3.5-turbo");
        setGenerationInputPrompt(settingsMap.get("description_generation_user_prompt") || "Generate description for [name_en] using [result]");
        setGenerationOutputPrompt(settingsMap.get("description_generation_prompt") || "");
        setGenerationOutputEnabled(settingsMap.get("ai_generation_output_enabled") === "true");
        setTestProductId(settingsMap.get("ai_description_test_product_id") || "");

        // Load last test result if exists
        const testResultJson = settingsMap.get("ai_description_last_test_result");
        if (testResultJson) {
          try {
            const parsed = JSON.parse(testResultJson) as TestResultData;
            setTestResult(parsed);
            console.log("Loaded previous test result from database");
          } catch (err) {
            console.warn("Failed to parse saved test result:", err);
          }
        }

        const chatbotRes = await fetch("/api/chatbot");
        if (chatbotRes.ok) {
          const data = (await chatbotRes.json()) as { models?: string[] };
          if (Array.isArray(data.models)) {
            setOllamaModels(data.models.map((name: string) => ({ value: name, label: name, description: "Ollama" })));
          }
        }
      } catch (error) {
        logClientError(error, { context: { source: "AiDescriptionSettings", action: "loadData" } });
        toast("Failed to load configuration.", { variant: "error" });
      } finally {
        setLoading(false);
      }
    };
    void loadData();
  }, [toast]);

  const handleTest = async (): Promise<void> => {
    if (!testProductId) {
      toast("Please enter a Product ID or SKU.", { variant: "error" });
      return;
    }

    setTesting(true);
    setTestResult(null);

    try {
      let product: ProductWithImages | null = null;
      const productRes = await fetch(`/api/products/${testProductId}`);

      if (productRes.ok) {
        product = (await productRes.json()) as ProductWithImages;
      } else {
        const skuRes = await fetch(`/api/products?sku=${testProductId}`);
        if (skuRes.ok) {
          const products = (await skuRes.json()) as ProductWithImages[];
          if (Array.isArray(products) && products.length > 0) {
            product = products[0] || null;
          }
        }
      }

      if (!product) {
        throw new Error(`Product not found: ${testProductId}`);
      }

      const uploadedImages = Array.isArray(product.images) 
        ? product.images.map((img: ProductImageRecord) => img.imageFile?.filepath).filter((p: string | undefined): p is string => Boolean(p)) 
        : [];
      const externalImages = Array.isArray(product.imageLinks) ? product.imageLinks : [];
      const allImageUrls = [...externalImages, ...uploadedImages];

      // Create a job for the test
      const enqueueRes = await fetch("/api/products/ai-jobs/enqueue", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          productId: product.id,
          type: "description_generation",
          payload: {
            productData: product,
            imageUrls: allImageUrls,
            visionOutputEnabled,
            generationOutputEnabled,
            isTest: true
          }
        }),
      });

      const enqueueData = (await enqueueRes.json()) as { error?: string; jobId: string };
      if (!enqueueRes.ok) {
        throw new Error(enqueueData.error || "Failed to enqueue test job.");
      }
      const jobId = enqueueData.jobId;

      // Poll for completion
      let completed = false;
      let attempts = 0;
      while (!completed && attempts < 60) { // 2 minutes max
        await new Promise((r: (value: void) => void) => setTimeout(r, 2000));
        const statusRes = await fetch(`/api/products/ai-jobs/${jobId}`);
        if (!statusRes.ok) break;
        const { job } = (await statusRes.json()) as { job: JobData };

        if (job.status === "completed") {
          const data = job.result;

          const newTestResult: TestResultData = {
            analysisInitial: data?.analysisInitial || data?.analysis || "",
            analysisFinal: data?.analysisFinal || "",
            descriptionInitial: data?.descriptionInitial || data?.description || "",
            descriptionFinal: data?.descriptionFinal || "",
          };

          setTestResult(newTestResult);

          // Save test result to database so it persists across page navigations
          try {
            await fetch("/api/settings", {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({
                key: "ai_description_last_test_result",
                value: JSON.stringify(newTestResult)
              }),
            });
          } catch (err) {
            logClientError(err, { context: { source: "AiDescriptionSettings", action: "saveTestResult", jobId } });
          }

          toast("Test completed. Results saved.", { variant: "success" });
          completed = true;
        } else if (job.status === "failed") {
          throw new Error(job.errorMessage || "Job failed.");
        } else if (job.status === "canceled") {
          throw new Error("Job was canceled.");
        }
        attempts++;
      }

      if (!completed) {
        throw new Error("Test timed out. Check the Jobs page.");
      }

    } catch (error) {
      logClientError(error, { context: { source: "AiDescriptionSettings", action: "handleTest", productId: testProductId } });
      toast(error instanceof Error ? error.message : "Test failed.", { variant: "error" });
    } finally {
      setTesting(false);
    }
  };

  const handleQueueAll = async (): Promise<void> => {
    if (!window.confirm("This will queue description generation for ALL products using the current configuration. Proceed?")) return;
    setQueuing(true);
    try {
      const res = await fetch("/api/products/ai-jobs/bulk", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          type: "description_generation",
          config: {
            visionOutputEnabled,
            generationOutputEnabled
          }
        }),
      });
      if (!res.ok) throw new Error("Failed to queue jobs.");
      const data = (await res.json()) as { count: number };
      toast(`Queued ${data.count} products for generation.`, { variant: "success" });
    } catch (error) {
      toast(error instanceof Error ? error.message : "Failed to queue jobs.", { variant: "error" });
    } finally {
      setQueuing(false);
    }
  };

  const handleSave = async (): Promise<void> => {
    setSaving(true);
    try {
      const payloads = [
        { key: "ai_vision_model", value: imageAnalysisModel },
        { key: "ai_vision_user_prompt", value: visionInputPrompt },
        { key: "ai_vision_prompt", value: visionOutputPrompt },
        { key: "ai_vision_output_enabled", value: String(visionOutputEnabled) },
        { key: "openai_model", value: descriptionGenerationModel },
        { key: "description_generation_user_prompt", value: generationInputPrompt },
        { key: "description_generation_prompt", value: generationOutputPrompt },
        { key: "ai_generation_output_enabled", value: String(generationOutputEnabled) },
        { key: "ai_description_test_product_id", value: testProductId },
      ];

      // Use TanStack Query mutation for settings updates
      for (const payload of payloads) {
        await updateSettingMutateAsync(payload);
      }

      // Also save to dedicated MongoDB collection
      await fetch("/api/ai-config", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          imageAnalysisModel,
          visionInputPrompt,
          visionOutputPrompt,
          visionOutputEnabled,
          descriptionGenerationModel,
          generationInputPrompt,
          generationOutputPrompt,
          generationOutputEnabled,
          testProductId,
        }),
      });

      toast("Settings saved.", { variant: "success" });
    } catch (error) {
      logClientError(error, { context: { source: "AiDescriptionSettings", action: "handleSave" } });
      toast("Failed to save.", { variant: "error" });
    } finally {
      setSaving(false);
    }
  };

  const copyResult = (text?: string): void => {
    if (!text) return;
    void navigator.clipboard.writeText(text);
    toast("Result copied to clipboard.");
  };

  const clearTestResults = async (): Promise<void> => {
    setTestResult(null);
    try {
      await fetch("/api/settings", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          key: "ai_description_last_test_result",
          value: ""
        }),
      });
      toast("Test results cleared.", { variant: "success" });
    } catch (err) {
      console.warn("Failed to clear test results from database:", err);
    }
  };

  if (loading) return <div className="text-sm text-gray-400">Loading settings...</div>;

  return (<>
    <div className="space-y-8">
      <div>
        <div className="flex items-center justify-between mb-6">
          <div>
            <h2 className="text-lg font-medium text-white mb-1">AI Description Configuration</h2>
            <p className="text-sm text-gray-400">Configure multi-step generation flow for product descriptions.</p>
          </div>
          <div className="flex items-center gap-2">
            <Input
              placeholder="Product ID or SKU"
              value={testProductId}
              onChange={(e: React.ChangeEvent<HTMLInputElement>) => setTestProductId(e.target.value)}
              className="w-[180px] bg-gray-900 border text-white h-9 text-sm"
            />
            <Button variant="secondary" onClick={() => void handleTest()} disabled={testing} className="gap-2 h-9">
              <PlayIcon className="size-3.5" />
              {testing ? "Testing..." : "Test on Product"}
            </Button>

            {testResult && (
              <Button variant="ghost" onClick={() => void clearTestResults()} className="gap-2 h-9 text-red-400 hover:text-red-300">
                <XCircle className="size-3.5" />
                Clear Results
              </Button>
            )}

            <Button variant="outline" onClick={() => void handleQueueAll()} disabled={queuing} className="gap-2 h-9 text-purple-400 border-purple-900/50 hover:bg-purple-950">
              <RefreshCcw className={`size-3.5 ${queuing ? "animate-spin" : ""}`} />
              {queuing ? "Queuing..." : "Queue for All"}
            </Button>

            <Dialog>
              <DialogTrigger asChild>
                <Button variant="outline" className="h-9 gap-2">
                  <InfoIcon className="size-4" />
                  Placeholders
                </Button>
              </DialogTrigger>
              <DialogContent className="max-w-md max-h-[80vh] overflow-y-auto">
                <DialogHeader>
                  <DialogTitle>Available Placeholders</DialogTitle>
                  <DialogDescription>Use these placeholders to inject dynamic data into your prompts.</DialogDescription>
                </DialogHeader>
                <div className="space-y-2 mt-4">
                  {AVAILABLE_PLACEHOLDERS.map((ph: { key: string, description: string }) => (
                    <div key={ph.key} className="flex items-center justify-between text-sm border-b border-border/50 pb-2 last:border-0 last:pb-0">
                      <code className="text-purple-400 font-bold bg-purple-500/10 px-1 py-0.5 rounded">[{ph.key}]</code>
                      <span className="text-gray-500 italic text-xs">{ph.description}</span>
                    </div>
                  ))}
                </div>
              </DialogContent>
            </Dialog>
          </div>
        </div>

        <SectionPanel className="space-y-6 p-6">
          {/* Path 1 */}
          <div className="space-y-4">
            <div className="flex items-center gap-2">
              <Badge variant="info" className="h-6 w-6 justify-center p-0 font-bold">1</Badge>
              <h3 className="text-md font-medium text-white">Signal Path 1: Image Analysis</h3>
            </div>

            <div className="pl-8 space-y-6">
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <Label>Input Prompt</Label>
                  <Textarea
                    rows={4}
                    value={visionInputPrompt}
                    onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => setVisionInputPrompt(e.target.value)}
                    className="mt-1.5 bg-gray-900 border text-white font-mono text-sm"
                  />
                </div>
                <div className="space-y-2">
                  <div className="flex items-center justify-between">
                    <Label>Initial Result</Label>
                    <Button variant="ghost" size="sm" className="h-6 text-[10px]" onClick={() => copyResult(testResult?.analysisInitial)}>
                      <CopyIcon className="size-3 mr-1"/>Copy
                    </Button>
                  </div>
                  <SectionPanel variant="subtle" className="mt-1.5 p-4 text-sm text-gray-300 h-[100px] overflow-y-auto border border-border font-mono">
                    {testResult?.analysisInitial ? (
                      <div className="whitespace-pre-wrap">{testResult.analysisInitial}</div>
                    ) : (
                      <span className="text-gray-600 italic text-xs">Waiting for test...</span>
                    )}
                  </SectionPanel>
                </div>
              </div>

              <div className="max-w-md">
                <Label>Vision Model</Label>
                <UnifiedSelect
                  value={imageAnalysisModel}
                  onValueChange={setImageAnalysisModel}
                  options={[...STATIC_VISION_MODELS, ...ollamaModels]}
                />
              </div>

              <div className="pt-4 border-t border-border/50 space-y-4">
                <div className="flex items-center gap-2">
                  <Checkbox 
                    id="v-output-enabled" 
                    checked={visionOutputEnabled} 
                    onCheckedChange={(checked: boolean | "indeterminate") => setVisionOutputEnabled(!!checked)} 
                  />
                  <Label htmlFor="v-output-enabled" className="text-blue-400 cursor-pointer">Enable Output Prompt (Refinement using {imageAnalysisModel})</Label>
                </div>
                {visionOutputEnabled && (
                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 animate-in fade-in slide-in-from-top-2 duration-300">
                    <div className="space-y-2">
                      <Label>Output Prompt</Label>
                      <Textarea
                        rows={4}
                        value={visionOutputPrompt}
                        onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => setVisionOutputPrompt(e.target.value)}
                        className="mt-1.5 bg-gray-900 border text-white font-mono text-sm"
                        placeholder="Refine result... use [result] for initial analysis."
                      />
                    </div>
                    <div className="space-y-2">
                      <div className="flex items-center justify-between">
                        <Label>Final Analysis</Label>
                        <Button variant="ghost" size="sm" className="h-6 text-[10px]" onClick={() => copyResult(testResult?.analysisFinal)}>
                          <CopyIcon className="size-3 mr-1"/>Copy
                        </Button>
                      </div>
                      <SectionPanel variant="subtle" className="mt-1.5 p-4 text-sm text-gray-300 h-[100px] overflow-y-auto border border-border font-mono">
                        {testResult?.analysisFinal ? (
                          <div className="whitespace-pre-wrap">{testResult.analysisFinal}</div>
                        ) : (
                          <span className="text-gray-600 italic text-xs">No result yet.</span>
                        )}
                      </SectionPanel>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>

          <div className="border-t border-border my-8"></div>

          {/* Path 2 */}
          <div className="space-y-4">
            <div className="flex items-center gap-2">
              <Badge variant="secondary" className="h-6 w-6 justify-center p-0 font-bold border-purple-500/30 bg-purple-500/20 text-purple-400">2</Badge>
              <h3 className="text-md font-medium text-white">Signal Path 2: Description Generation</h3>
            </div>

            <div className="pl-8 space-y-6">
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <Label>Input Prompt</Label>
                  <Textarea
                    rows={6}
                    value={generationInputPrompt}
                    onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => setGenerationInputPrompt(e.target.value)}
                    className="mt-1.5 bg-gray-900 border text-white font-mono text-sm"
                  />
                </div>
                <div className="space-y-2">
                  <div className="flex items-center justify-between">
                    <Label>Initial Description</Label>
                    <Button variant="ghost" size="sm" className="h-6 text-[10px]" onClick={() => copyResult(testResult?.descriptionInitial)}>
                      <CopyIcon className="size-3 mr-1"/>Copy
                    </Button>
                  </div>
                  <SectionPanel variant="subtle" className="mt-1.5 p-4 text-sm text-gray-300 h-[132px] overflow-y-auto border border-border font-sans">
                    {testResult?.descriptionInitial ? (
                      <div className="whitespace-pre-wrap">{testResult.descriptionInitial}</div>
                    ) : (
                      <span className="text-gray-600 italic text-xs">Waiting for test...</span>
                    )}
                  </SectionPanel>
                </div>
              </div>

              <div className="max-w-md">
                <Label>Generation Model</Label>
                <UnifiedSelect
                  value={descriptionGenerationModel}
                  onValueChange={setDescriptionGenerationModel}
                  options={[...STATIC_TEXT_MODELS, ...ollamaModels]}
                />
              </div>

              <div className="pt-4 border-t border-border/50 space-y-4">
                <div className="flex items-center gap-2">
                  <Checkbox 
                    id="g-output-enabled" 
                    checked={generationOutputEnabled} 
                    onCheckedChange={(checked: boolean | "indeterminate") => setGenerationOutputEnabled(!!checked)} 
                  />
                  <Label htmlFor="g-output-enabled" className="text-purple-400 cursor-pointer">Enable Output Prompt (Refinement using {descriptionGenerationModel})</Label>
                </div>
                {generationOutputEnabled && (
                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 animate-in fade-in slide-in-from-top-2 duration-300">
                    <div className="space-y-2">
                      <Label>Output Prompt</Label>
                      <Textarea
                        rows={6}
                        value={generationOutputPrompt}
                        onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => setGenerationOutputPrompt(e.target.value)}
                        className="mt-1.5 bg-gray-900 border text-white font-mono text-sm"
                        placeholder="Final polish... use [result] for initial description."
                      />
                    </div>
                    <div className="space-y-2">
                      <div className="flex items-center justify-between">
                        <Label>Final Description</Label>
                        <Button variant="ghost" size="sm" className="h-6 text-[10px]" onClick={() => copyResult(testResult?.descriptionFinal)}>
                          <CopyIcon className="size-3 mr-1"/>Copy
                        </Button>
                      </div>
                      <SectionPanel variant="subtle" className="mt-1.5 p-4 text-sm text-gray-300 h-[132px] overflow-y-auto border border-border font-sans">
                        {testResult?.descriptionFinal ? (
                          <div className="whitespace-pre-wrap">{testResult.descriptionFinal}</div>
                        ) : (
                          <span className="text-gray-600 italic text-xs">No result yet.</span>
                        )}
                      </SectionPanel>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        </SectionPanel>
      </div>

      <div className="flex justify-end">
        <Button onClick={() => void handleSave()} disabled={saving} className="bg-white text-black hover:bg-gray-200">
          {saving ? "Saving..." : "Save Configuration"}
        </Button>
      </div>
    </div>
  </>);
}

"use client";

import { Canvas, useFrame, useThree } from "@react-three/fiber";
import {
  OrbitControls,
  Center,
  useGLTF,
  Environment,
  Html,
  ContactShadows,
  useProgress,
  Bounds,
  PresentationControls,
} from "@react-three/drei";
import { EffectComposer, Bloom, SMAA, ToneMapping, Vignette } from "@react-three/postprocessing";
import { Suspense, useEffect, useRef, useMemo, Component, ErrorInfo } from "react";
import * as THREE from "three";
import { DitheringPass } from "./shaders/DitheringEffect";
import { PixelationPass } from "./shaders/PixelationEffect";
import { OrderedDitheringPass } from "./shaders/OrderedDitheringEffect";
import { ToneMappingMode, BlendFunction } from "postprocessing";

// Error Boundary for 3D components
class Model3DErrorBoundary extends Component<
  { children: React.ReactNode; onError?: (error: Error) => void },
  { hasError: boolean; error?: Error }
> {
  constructor(props: { children: React.ReactNode; onError?: (error: Error) => void }) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(error: Error): { hasError: boolean; error: Error } {
    return { hasError: true, error };
  }

  override componentDidCatch(error: Error, errorInfo: ErrorInfo): void {
    console.error("3D Model Error:", error, errorInfo);
    this.props.onError?.(error);
  }

  override render(): React.ReactNode {
    if (this.state.hasError) {
      return (
        <Html center>
          <div className="text-red-400 text-center p-4 bg-black/50 rounded">
            <p>Failed to load 3D model</p>
            <p className="text-sm text-gray-400 mt-2">
              {this.state.error?.message || "Unknown error occurred"}
            </p>
          </div>
        </Html>
      );
    }

    return this.props.children;
  }
}

// Loading progress component
function Loader(): React.JSX.Element {
  const { progress } = useProgress();
  return (
    <Html center>
      <div className="flex flex-col items-center gap-3">
        <div className="relative h-16 w-16">
          <svg className="h-16 w-16 -rotate-90" viewBox="0 0 36 36">
            <circle
              cx="18"
              cy="18"
              r="16"
              fill="none"
              className="stroke-gray-700"
              strokeWidth="2"
            />
            <circle
              cx="18"
              cy="18"
              r="16"
              fill="none"
              className="stroke-blue-500"
              strokeWidth="2"
              strokeDasharray={100}
              strokeDashoffset={100 - progress}
              strokeLinecap="round"
            />
          </svg>
          <span className="absolute inset-0 flex items-center justify-center text-xs font-medium text-white">
            {Math.round(progress)}%
          </span>
        </div>
        <span className="text-sm text-gray-400">Loading model...</span>
      </div>
    </Html>
  );
}

// Enhanced model component with PBR material optimization
interface Model3DProps {
  url: string;
  onLoad?: () => void;
  onError?: (error: Error) => void;
  castShadow?: boolean;
  receiveShadow?: boolean;
  position?: [number, number, number];
  rotation?: [number, number, number];
  scale?: number | [number, number, number];
}

function AutoRotateGroup({
  enabled,
  speed,
  children,
}: {
  enabled: boolean;
  speed: number;
  children: React.ReactNode;
}): React.JSX.Element {
  const ref = useRef<THREE.Group>(null);
  useFrame((_, delta) => {
    if (!enabled || !ref.current) return;
    ref.current.rotation.y += delta * speed * 0.6;
  });
  return <group ref={ref}>{children}</group>;
}

function Model3D({
  url,
  onLoad,
  onError,
  castShadow = true,
  receiveShadow = true,
  position,
  rotation,
  scale,
}: Model3DProps): React.JSX.Element {
  const { scene } = useGLTF(url, true); // Enable error handling
  const modelRef = useRef<THREE.Group>(null);

  useEffect(() => {
    if (scene) {
      // Optimize materials for PBR rendering
      scene.traverse((child: THREE.Object3D) => {
        if (child instanceof THREE.Mesh) {
          child.castShadow = castShadow;
          child.receiveShadow = receiveShadow;

          // Enhance material properties for better realism
          if (child.material instanceof THREE.MeshStandardMaterial) {
            child.material.envMapIntensity = 1.5;
            child.material.needsUpdate = true;
          }
        }
      });
      onLoad?.();
    }
  }, [scene, onLoad, castShadow, receiveShadow]);

  useEffect(() => {
    if (!scene && onError) {
      onError(new Error("Failed to load model"));
    }
  }, [scene, onError]);

  if (!scene) {
    return (
      <Html center>
        <div className="text-red-400 text-center p-4 bg-black/50 rounded">
          <p>Model not found</p>
          <p className="text-sm text-gray-400 mt-2">
            The 3D asset could not be loaded
          </p>
        </div>
      </Html>
    );
  }

  /* eslint-disable react/no-unknown-property */
  return (
    <primitive
      ref={modelRef}
      object={scene}
      dispose={null}
      position={position}
      rotation={rotation}
      scale={scale}
    />
  );
  /* eslint-enable react/no-unknown-property */
}

// Ground plane with realistic shadows
function Ground({ visible = true }: { visible?: boolean }): React.JSX.Element | null {
  if (!visible) return null;

  /* eslint-disable react/no-unknown-property */
  return (
    <mesh
      rotation={[-Math.PI / 2, 0, 0]}
      position={[0, -0.001, 0]}
      receiveShadow
    >
      <planeGeometry args={[50, 50]} />
      <shadowMaterial
        transparent
        opacity={0.4}
      />
    </mesh>
  );
  /* eslint-enable react/no-unknown-property */
}

// Scene lighting setup
interface SceneLightingProps {
  preset: LightingPreset;
  intensity?: number;
}

function SceneLighting({ preset, intensity = 1 }: SceneLightingProps): React.JSX.Element {
  const lightConfigs = {
    studio: {
      ambient: 0.4,
      main: { position: [5, 5, 5] as [number, number, number], intensity: 1.2 },
      fill: { position: [-5, 3, -5] as [number, number, number], intensity: 0.5 },
      rim: { position: [0, 5, -10] as [number, number, number], intensity: 0.8 },
    },
    outdoor: {
      ambient: 0.3,
      main: { position: [10, 10, 5] as [number, number, number], intensity: 1.5 },
      fill: { position: [-5, 2, 5] as [number, number, number], intensity: 0.3 },
      rim: { position: [0, 8, -8] as [number, number, number], intensity: 0.4 },
    },
    dramatic: {
      ambient: 0.15,
      main: { position: [3, 8, 3] as [number, number, number], intensity: 2 },
      fill: { position: [-8, 2, -3] as [number, number, number], intensity: 0.2 },
      rim: { position: [-3, 5, -8] as [number, number, number], intensity: 1.2 },
    },
    soft: {
      ambient: 0.6,
      main: { position: [5, 5, 5] as [number, number, number], intensity: 0.8 },
      fill: { position: [-5, 5, 5] as [number, number, number], intensity: 0.6 },
      rim: { position: [0, 3, -5] as [number, number, number], intensity: 0.4 },
    },
  };

  const config = lightConfigs[preset] || lightConfigs.studio;

  /* eslint-disable react/no-unknown-property */
  return (
    <>
      <ambientLight intensity={config.ambient * intensity} />
      <directionalLight
        position={config.main.position}
        intensity={config.main.intensity * intensity}
        castShadow
        shadow-mapSize={[2048, 2048]}
        shadow-camera-far={50}
        shadow-camera-left={-10}
        shadow-camera-right={10}
        shadow-camera-top={10}
        shadow-camera-bottom={-10}
        shadow-bias={-0.0001}
      />
      <directionalLight
        position={config.fill.position}
        intensity={config.fill.intensity * intensity}
      />
      <directionalLight
        position={config.rim.position}
        intensity={config.rim.intensity * intensity}
      />
    </>
  );
  /* eslint-enable react/no-unknown-property */
}

// Camera auto-framing
function CameraController({ autoFit }: { autoFit?: boolean }): null {
  const { camera, scene } = useThree();

  useEffect(() => {
    if (autoFit) {
      const box = new THREE.Box3().setFromObject(scene);
      const size = box.getSize(new THREE.Vector3());
      const center = box.getCenter(new THREE.Vector3());

      const maxDim = Math.max(size.x, size.y, size.z);
      const fov = (camera as THREE.PerspectiveCamera).fov * (Math.PI / 180);
      let distance = maxDim / (2 * Math.tan(fov / 2));
      distance *= 1.5; // Add some padding

      camera.position.set(center.x + distance * 0.5, center.y + distance * 0.3, center.z + distance);
      camera.lookAt(center);
      camera.updateProjectionMatrix();
    }
  }, [autoFit, camera, scene]);

  return null;
}

export type LightingPreset = "studio" | "outdoor" | "dramatic" | "soft";
export type EnvironmentPreset = "studio" | "sunset" | "dawn" | "night" | "warehouse" | "forest" | "apartment" | "city" | "park" | "lobby";

export interface Viewer3DProps {
  /** URL to the 3D model file (.glb or .gltf) */
  modelUrl: string;
  /** Background color */
  backgroundColor?: string;
  /** Enable dithering post-processing effect */
  enableDithering?: boolean;
  /** Dithering intensity (0-2, default 1) */
  ditheringIntensity?: number;
  /** Enable ordered dithering shader */
  enableOrderedDithering?: boolean;
  /** Dither grid size (2-12, default 4) */
  orderedDitheringGridSize?: number;
  /** Dither pixel size ratio (0.5-3, default 1) */
  orderedDitheringPixelSizeRatio?: number;
  /** Dither grayscale only */
  orderedDitheringGrayscaleOnly?: boolean;
  /** Dither invert colors */
  orderedDitheringInvertColor?: boolean;
  /** Dither luminance method (0=Average, 1=Rec.601, 2=Rec.709, 3=Max) */
  orderedDitheringLuminanceMethod?: number;
  /** Enable pixelation (pixel art effect) */
  enablePixelation?: boolean;
  /** Pixel size in screen pixels (1-32, default 6) */
  pixelSize?: number;
  /** Container class name */
  className?: string;
  /** Callback when model loads */
  onLoad?: () => void;
  /** Callback on load error */
  onError?: (error: Error) => void;
  /** Enable auto-rotation */
  autoRotate?: boolean;
  /** Auto-rotation speed */
  autoRotateSpeed?: number;
  /** Environment preset for HDR lighting */
  environment?: EnvironmentPreset;
  /** Lighting preset */
  lighting?: LightingPreset;
  /** Light intensity multiplier */
  lightIntensity?: number;
  /** Enable shadows */
  enableShadows?: boolean;
  /** Enable bloom effect */
  enableBloom?: boolean;
  /** Bloom intensity */
  bloomIntensity?: number;
  /** Enable tone mapping */
  enableToneMapping?: boolean;
  /** Tone mapping exposure */
  exposure?: number;
  /** Show ground plane */
  showGround?: boolean;
  /** Enable contact shadows */
  enableContactShadows?: boolean;
  /** Enable vignette effect */
  enableVignette?: boolean;
  /** Auto-fit camera to model */
  autoFit?: boolean;
  /** Enable anti-aliasing */
  enableAntiAliasing?: boolean;
  /** Use presentation controls (drag to rotate) */
  presentationMode?: boolean;
  /** Allow user interaction (orbit/pan/zoom) */
  allowUserControls?: boolean;
  /** Model position [x, y, z] */
  modelPosition?: [number, number, number];
  /** Model rotation [x, y, z] in radians */
  modelRotation?: [number, number, number];
  /** Model scale (number or [x, y, z]) */
  modelScale?: number | [number, number, number];
}

export function Viewer3D({
  modelUrl,
  backgroundColor = "#1a1a2e",
  enableDithering = false,
  ditheringIntensity = 1.0,
  enableOrderedDithering = false,
  orderedDitheringGridSize = 4,
  orderedDitheringPixelSizeRatio = 1,
  orderedDitheringGrayscaleOnly = false,
  orderedDitheringInvertColor = false,
  orderedDitheringLuminanceMethod = 1,
  enablePixelation = false,
  pixelSize = 6,
  className,
  onLoad,
  onError,
  autoRotate = true,
  autoRotateSpeed = 2,
  environment = "studio",
  lighting = "studio",
  lightIntensity = 1,
  enableShadows = true,
  enableBloom = false,
  bloomIntensity = 0.5,
  enableToneMapping = true,
  exposure = 1,
  showGround = false,
  enableContactShadows = true,
  enableVignette = false,
  autoFit = true,
  enableAntiAliasing = true,
  presentationMode = false,
  allowUserControls = true,
  modelPosition,
  modelRotation,
  modelScale,
}: Viewer3DProps): React.JSX.Element {
  const hasPostProcessing =
    enableDithering ||
    enableOrderedDithering ||
    enablePixelation ||
    enableBloom ||
    enableToneMapping ||
    enableVignette ||
    enableAntiAliasing;

  const effects = useMemo(() => {
    const effectsList: React.ReactElement[] = [];
    if (enableAntiAliasing) effectsList.push(<SMAA key="smaa" />);
    if (enableToneMapping) effectsList.push(<ToneMapping key="tonemapping" mode={ToneMappingMode.ACES_FILMIC} />);
    if (enableBloom) effectsList.push(<Bloom key="bloom" intensity={bloomIntensity} luminanceThreshold={0.9} luminanceSmoothing={0.025} />);
    if (enableVignette) effectsList.push(<Vignette key="vignette" offset={0.3} darkness={0.5} blendFunction={BlendFunction.NORMAL} />);
    if (enablePixelation) effectsList.push(<PixelationPass key="pixelation" pixelSize={Math.max(1, pixelSize)} />);
    if (enableOrderedDithering) {
      effectsList.push(
        <OrderedDitheringPass
          key="ordered-dithering"
          gridSize={orderedDitheringGridSize}
          pixelSizeRatio={orderedDitheringPixelSizeRatio}
          grayscaleOnly={orderedDitheringGrayscaleOnly}
          invertColor={orderedDitheringInvertColor}
          luminanceMethod={orderedDitheringLuminanceMethod}
        />
      );
    }
    if (enableDithering) effectsList.push(<DitheringPass key="dithering" intensity={ditheringIntensity} />);
    return effectsList;
  }, [
    enableAntiAliasing,
    enableToneMapping,
    enableBloom,
    bloomIntensity,
    enableVignette,
    enablePixelation,
    pixelSize,
    enableOrderedDithering,
    orderedDitheringGridSize,
    orderedDitheringPixelSizeRatio,
    orderedDitheringGrayscaleOnly,
    orderedDitheringInvertColor,
    orderedDitheringLuminanceMethod,
    enableDithering,
    ditheringIntensity,
  ]);

  return (
    <div className={className}>
      <Canvas
        camera={{ position: [0, 0, 5], fov: 45, near: 0.1, far: 1000 }}
        shadows={enableShadows}
        gl={{
          preserveDrawingBuffer: true,
          antialias: !hasPostProcessing, // Disable if using SMAA
          toneMapping: enableToneMapping ? THREE.ACESFilmicToneMapping : THREE.NoToneMapping,
          toneMappingExposure: exposure,
          outputColorSpace: THREE.SRGBColorSpace,
        }}
        dpr={[1, 2]} // Responsive pixel ratio
      >
        {/* eslint-disable react/no-unknown-property */}
        <color attach="background" args={[backgroundColor]} />
        {/* eslint-enable react/no-unknown-property */}

        {/* Lighting */}
        <SceneLighting preset={lighting} intensity={lightIntensity} />

        {/* HDR Environment */}
        <Environment preset={environment} background={false} />

        <Suspense fallback={<Loader />}>
          {presentationMode && allowUserControls ? (
            <PresentationControls
              global
              rotation={[0, 0, 0]}
              polar={[-Math.PI / 4, Math.PI / 4]}
              azimuth={[-Math.PI / 4, Math.PI / 4]}
            >
              <Center>
                <Bounds fit clip observe margin={1.2}>
                  <Model3DErrorBoundary {...(onError && { onError })}>
                    <Model3D
                      url={modelUrl}
                      {...(onLoad && { onLoad })}
                      {...(onError && { onError })}
                      castShadow={enableShadows}
                      receiveShadow={enableShadows}
                      {...(modelPosition && { position: modelPosition })}
                      {...(modelRotation && { rotation: modelRotation })}
                      {...(modelScale && { scale: modelScale })}
                    />
                  </Model3DErrorBoundary>
                </Bounds>
              </Center>
            </PresentationControls>
          ) : (
            <Center>
              <Bounds fit clip observe margin={1.2}>
                <Model3DErrorBoundary {...(onError && { onError })}>
                  <AutoRotateGroup enabled={!allowUserControls && autoRotate} speed={autoRotateSpeed}>
                    <Model3D
                      url={modelUrl}
                      {...(onLoad && { onLoad })}
                      {...(onError && { onError })}
                      castShadow={enableShadows}
                      receiveShadow={enableShadows}
                      {...(modelPosition && { position: modelPosition })}
                      {...(modelRotation && { rotation: modelRotation })}
                      {...(modelScale && { scale: modelScale })}
                    />
                  </AutoRotateGroup>
                </Model3DErrorBoundary>
              </Bounds>
            </Center>
          )}

          {/* Ground and shadows */}
          {showGround && <Ground visible={showGround} />}

          {enableContactShadows && (
            <ContactShadows
              opacity={0.5}
              scale={10}
              blur={2}
              far={4}
              resolution={256}
              color="#000000"
            />
          )}
        </Suspense>

        {/* Camera Controls */}
        {!presentationMode && allowUserControls && (
          <OrbitControls
            autoRotate={autoRotate}
            autoRotateSpeed={autoRotateSpeed}
            enablePan={allowUserControls}
            enableZoom={allowUserControls}
            enableRotate={allowUserControls}
              enableDamping={true}
              dampingFactor={0.05}
              minDistance={0.5}
              maxDistance={100}
              minPolarAngle={0}
            maxPolarAngle={Math.PI}
          />
        )}

        <CameraController autoFit={autoFit} />

        {/* Post-processing */}
        {hasPostProcessing && effects.length > 0 && (
          <EffectComposer multisampling={0}>
            {effects}
          </EffectComposer>
        )}
      </Canvas>
    </div>
  );
}

// Preload models for better performance
export function preloadModel(url: string): void {
  useGLTF.preload(url);
}

